  array or tuple, and it stops advancing the iterator as soon as it encounters
  the first `Nothing`.

  ```ts
  import * as maybe from 'true-myth/maybe';

  maybe.sequence([maybe.just(1), maybe.just(2)]); // Just([1, 2])
  maybe.sequence([maybe.just(1), maybe.nothing()]); // Nothing
  ```

  @param items The `Maybe`s to resolve to a single `Maybe`.
 */
export function sequence<T extends {}>(items: Iterable<Maybe<T>>): Maybe<T[]> {
  const values: T[] = [];
  for (const item of items) {
    if (item.isNothing) {
      return nothing();
    }

    values.push(item.value);
  }

  return just(values);
}

